// Mapează platforma din frontend la marketplace-ul canonic din catalogs
const body = $input.first().json.body || {};
const platform = (body.platform || 'emag').toLowerCase();
const platformMap = {
  'emag': 'emag_ro',
  'trendyol': 'trendyol_ro',
  'temu': 'temu_ro'
};
const marketplace = platformMap[platform] || (platform + '_ro');
const searchTerm = (body.search || '').trim();

return [{ json: { marketplace, searchTerm } }];

// Formatează rezultatele Postgres în structura așteptată de frontend.
// Include și name_ro (traducere română) pentru afișare bilingvă + search bilingv.
const rows = $input.all().map(item => item.json);

// Dacă Postgres a returnat un singur obiect gol (no results), returnăm array gol
if (rows.length === 1 && !rows[0].category_id) {
  return [{ json: { categories: [] } }];
}

const categories = rows.map(row => ({
  id: String(row.category_id),
  name: row.category_name,
  nameRo: row.name_ro || null
}));

return [{ json: { categories } }];
